import{f as d,D as c,o as a,c as b,a2 as e,b as l,w as n,a as t,G as i,a5 as r}from"./chunks/framework.Ccw_j35p.js";const B=JSON.parse('{"title":"Redis 核心原理","description":"","frontmatter":{},"headers":[],"relativePath":"database/redis/index.md","filePath":"database/redis/index.md","lastUpdated":1780734044000}'),o={name:"database/redis/index.md"};function u(m,s,h,g,E,k){const p=c("Mermaid");return a(),b("div",null,[s[2]||(s[2]=e('<h1 id="redis-核心原理" tabindex="-1">Redis 核心原理 <a class="header-anchor" href="#redis-核心原理" aria-label="Permalink to &quot;Redis 核心原理&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Redis（Remote Dictionary Server）是业界最流行的内存数据库，面试中与 MySQL 并列为必问项。本章聚焦三个维度：<strong>8 种数据类型</strong>（5 种基础 + 3 种高级）、<strong>单线程模型</strong>（为什么快）、<strong>使用场景</strong>（知道数据类型还要知道怎么用）。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>能说出每种数据类型的底层编码结构，理解单线程 IO 多路复用模型，针对业务场景选择合适的 Redis 数据类型并设计合理的 Key 结构。</p></div><hr><h2 id="一、5-种基本数据类型" tabindex="-1">一、5 种基本数据类型 <a class="header-anchor" href="#一、5-种基本数据类型" aria-label="Permalink to &quot;一、5 种基本数据类型&quot;">​</a></h2><p>⭐ <strong>先把 5 种基本类型吃透，面试中 80% 的问题都围绕它们展开。</strong></p>',7)),(a(),l(r,null,{default:n(()=>[i(p,{id:"mermaid-21",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20Strings%5B%221.%20String%EF%BC%88%E5%AD%97%E7%AC%A6%E4%B8%B2%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20A1%5B%22SET%20%2F%20GET%20%2F%20INCR%22%5D%0A%20%20%20%20%20%20%20%20A2%5B%22%E5%BA%95%E5%B1%82%EF%BC%9ASDS%3Cbr%2F%3E%EF%BC%88embstr%20%2F%20raw%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Hashes%5B%222.%20Hash%EF%BC%88%E5%93%88%E5%B8%8C%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20B1%5B%22HSET%20%2F%20HGET%20%2F%20HMGET%22%5D%0A%20%20%20%20%20%20%20%20B2%5B%22%E5%BA%95%E5%B1%82%EF%BC%9Alistpack%20%E2%86%92%20hashtable%3Cbr%2F%3E%EF%BC%88ziplist%207.0%20%E5%BA%9F%E5%BC%83%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Lists%5B%223.%20List%EF%BC%88%E5%88%97%E8%A1%A8%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20C1%5B%22LPUSH%20%2F%20RPOP%20%2F%20LRANGE%22%5D%0A%20%20%20%20%20%20%20%20C2%5B%22%E5%BA%95%E5%B1%82%EF%BC%9Aquicklist%3Cbr%2F%3E%EF%BC%88ziplist%20%2B%20linkedlist%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Sets%5B%224.%20Set%EF%BC%88%E9%9B%86%E5%90%88%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20D1%5B%22SADD%20%2F%20SINTER%20%2F%20SDIFF%22%5D%0A%20%20%20%20%20%20%20%20D2%5B%22%E5%BA%95%E5%B1%82%EF%BC%9Alistpack%20%E2%86%92%20hashtable%3Cbr%2F%3E%EF%BC%88intset%20%E8%BF%87%E6%B8%A1%EF%BC%89%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20ZSets%5B%225.%20ZSet%EF%BC%88%E6%9C%89%E5%BA%8F%E9%9B%86%E5%90%88%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20E1%5B%22ZADD%20%2F%20ZRANGE%20%2F%20ZRANK%22%5D%0A%20%20%20%20%20%20%20%20E2%5B%22%E5%BA%95%E5%B1%82%EF%BC%9Alistpack%20%E2%86%92%20skiplist%20%2B%20hashtable%22%5D%0A%20%20%20%20end%0A"})]),fallback:n(()=>[...s[0]||(s[0]=[t(" Loading... ",-1)])]),_:1})),s[3]||(s[3]=e(`<h3 id="_1-1-string-字符串" tabindex="-1">1.1 String（字符串） <a class="header-anchor" href="#_1-1-string-字符串" aria-label="Permalink to &quot;1.1 String（字符串）&quot;">​</a></h3><p>⭐ <strong>最基础的类型，也是分布式锁、计数器、缓存对象的基础。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>编码结构：SDS（Simple Dynamic String）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>传统 C 字符串的问题：</span></span>
<span class="line"><span>  获取长度 O(n) → SDS 维护 len 字段 → O(1)</span></span>
<span class="line"><span>  缓冲区溢出    → SDS 自动扩容</span></span>
<span class="line"><span>  二进制不安全  → SDS 用 len 界定长度，可存任意二进制</span></span>
<span class="line"><span></span></span>
<span class="line"><span>编码选择：</span></span>
<span class="line"><span>  长度 ≤ 44 字节 → embstr 编码（一次内存分配，只读）</span></span>
<span class="line"><span>  长度 &gt; 44 字节 → raw 编码（两次内存分配，可修改）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>时间复杂度</th></tr></thead><tbody><tr><td><code>SET key value [EX seconds]</code></td><td>设置值，可带过期时间</td><td>O(1)</td></tr><tr><td><code>GET key</code></td><td>获取值</td><td>O(1)</td></tr><tr><td><code>INCR key</code> / <code>DECR key</code></td><td>原子增减</td><td>O(1)</td></tr><tr><td><code>SETNX key value</code></td><td>不存在才设置（分布式锁基础）</td><td>O(1)</td></tr><tr><td><code>MGET k1 k2 ...</code></td><td>批量获取（减少 RTT）</td><td>O(N)</td></tr><tr><td><code>GETRANGE key start end</code></td><td>截取子串</td><td>O(N)</td></tr></tbody></table><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- 基础读写</span></span>
<span class="line"><span>SET user:1001:name &quot;张三&quot; EX 3600</span></span>
<span class="line"><span>GET user:1001:name</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 分布式锁（SET NX EX 原子操作）</span></span>
<span class="line"><span>SET lock:order:1001 &quot;uuid-xxxx&quot; NX EX 10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 计数器（文章阅读量）</span></span>
<span class="line"><span>INCR article:998:views</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 批量获取（减少网络往返）</span></span>
<span class="line"><span>MGET user:1001:name user:1002:name user:1003:name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">面试高频问题</p><p><strong>Q: <code>SETNX</code> + <code>EXPIRE</code> 为什么不能分开写？</strong></p><p>A: 不是原子操作。如果 <code>SETNX</code> 成功后服务宕机，<code>EXPIRE</code> 未执行，锁永远不会释放 → 死锁。必须用 <code>SET key value NX EX seconds</code>。</p></div><h3 id="_1-2-hash-哈希" tabindex="-1">1.2 Hash（哈希） <a class="header-anchor" href="#_1-2-hash-哈希" aria-label="Permalink to &quot;1.2 Hash（哈希）&quot;">​</a></h3><p>⭐ <strong>适合存储&quot;对象&quot;，比 String 序列化 JSON 更节省内存。</strong></p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>时间复杂度</th></tr></thead><tbody><tr><td><code>HSET key field value</code></td><td>设置字段</td><td>O(1)</td></tr><tr><td><code>HGET key field</code></td><td>获取字段</td><td>O(1)</td></tr><tr><td><code>HGETALL key</code></td><td>获取所有字段</td><td>O(N)</td></tr><tr><td><code>HMGET key f1 f2 ...</code></td><td>批量获取</td><td>O(N)</td></tr><tr><td><code>HINCRBY key field N</code></td><td>原子增减</td><td>O(1)</td></tr></tbody></table><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- 用户信息（用 Hash 存对象，比 JSON String 更灵活）</span></span>
<span class="line"><span>HSET user:1001 name &quot;张三&quot; age 25 city &quot;北京&quot;</span></span>
<span class="line"><span>HGET user:1001 name</span></span>
<span class="line"><span>HMGET user:1001 name age city</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 购物车（用户ID → {商品ID: 数量}）</span></span>
<span class="line"><span>HSET cart:1001 sku:998 2 sku:997 1</span></span>
<span class="line"><span>HINCRBY cart:1001 sku:998 1   -- 数量 +1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>编码演进：</span></span>
<span class="line"><span>  字段少/值小 → listpack（紧凑连续内存，节省空间）</span></span>
<span class="line"><span>  超过阈值    → hashtable（标准哈希表，O(1) 查找）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>阈值配置：</span></span>
<span class="line"><span>  hash-max-listpack-entries 512  （字段数上限）</span></span>
<span class="line"><span>  hash-max-listpack-value 64     （单字段值长度上限）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_1-3-list-列表" tabindex="-1">1.3 List（列表） <a class="header-anchor" href="#_1-3-list-列表" aria-label="Permalink to &quot;1.3 List（列表）&quot;">​</a></h3><p>⭐ <strong>底层是 quicklist，兼顾了内存效率和操作性能。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>quicklist 结构：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  quicklist</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├── quicklistNode → [ziplist] → 元素1..元素N</span></span>
<span class="line"><span>      ├── quicklistNode → [ziplist] → 元素N+1..元素2N</span></span>
<span class="line"><span>      ├── quicklistNode → [ziplist] → ...</span></span>
<span class="line"><span>      └── quicklistNode → [ziplist] → ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个节点存一个压缩列表（listpack/ziplist），双向链表串联：</span></span>
<span class="line"><span>  - 头/尾操作 O(1)</span></span>
<span class="line"><span>  - 中间节点按需解压（懒惰解压）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>时间复杂度</th></tr></thead><tbody><tr><td><code>LPUSH / RPUSH key val</code></td><td>左/右入队</td><td>O(1)</td></tr><tr><td><code>LPOP / RPOP key</code></td><td>左/右出队</td><td>O(1)</td></tr><tr><td><code>LRANGE key start end</code></td><td>范围获取</td><td>O(S+N)</td></tr><tr><td><code>LTRIM key start end</code></td><td>裁剪列表</td><td>O(N)</td></tr><tr><td><code>BLPOP key timeout</code></td><td>阻塞出队（消息队列核心）</td><td>O(1)</td></tr></tbody></table><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- 最新评论列表（LPUSH + LTRIM 保持固定长度）</span></span>
<span class="line"><span>LPUSH article:998:comments &quot;{user:&#39;张三&#39;,text:&#39;写得好&#39;}&quot;</span></span>
<span class="line"><span>LPUSH article:998:comments &quot;{user:&#39;李四&#39;,text:&#39;学习了&#39;}&quot;</span></span>
<span class="line"><span>LTRIM article:998:comments 0 99    -- 只保留最新 100 条</span></span>
<span class="line"><span>LRANGE article:998:comments 0 9    -- 分页查询第 1 页</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 简单消息队列（BLPOP 阻塞等待）</span></span>
<span class="line"><span>-- 生产者</span></span>
<span class="line"><span>LPUSH task:queue &quot;task_data_1&quot;</span></span>
<span class="line"><span>-- 消费者（阻塞 5 秒等待消息）</span></span>
<span class="line"><span>BLPOP task:queue 5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">慎用场景</p><p>List 做消息队列没有 ACK 机制，消费者崩溃消息丢失。生产环境消息队列建议用 Redis Stream 或 RabbitMQ / Kafka。</p></div><h3 id="_1-4-set-集合" tabindex="-1">1.4 Set（集合） <a class="header-anchor" href="#_1-4-set-集合" aria-label="Permalink to &quot;1.4 Set（集合）&quot;">​</a></h3><p>⭐ <strong>无序、不重复，核心价值是 O(1) 的交并差集运算。</strong></p><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>时间复杂度</th></tr></thead><tbody><tr><td><code>SADD key member</code></td><td>添加成员</td><td>O(1)</td></tr><tr><td><code>SISMEMBER key member</code></td><td>判断成员是否存在</td><td>O(1)</td></tr><tr><td><code>SINTER k1 k2</code></td><td>交集</td><td>O(N*M)</td></tr><tr><td><code>SUNION k1 k2</code></td><td>并集</td><td>O(N)</td></tr><tr><td><code>SDIFF k1 k2</code></td><td>差集</td><td>O(N)</td></tr><tr><td><code>SCARD key</code></td><td>集合大小</td><td>O(1)</td></tr><tr><td><code>SRANDMEMBER key N</code></td><td>随机取 N 个</td><td>O(N)</td></tr><tr><td><code>SPOP key N</code></td><td>随机弹出 N 个（抽奖）</td><td>O(N)</td></tr></tbody></table><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- 点赞用户集合</span></span>
<span class="line"><span>SADD article:998:likes user:1001 user:1002 user:1003</span></span>
<span class="line"><span>SISMEMBER article:998:likes user:1001  -- 检查是否点过赞</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 共同好友（交集）</span></span>
<span class="line"><span>SINTER user:1001:friends user:1002:friends</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 可能认识的人（差集：我的好友有，你的好友没有）</span></span>
<span class="line"><span>SDIFF user:1001:friends user:1002:friends</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 抽奖（随机弹出 N 个）</span></span>
<span class="line"><span>SPOP lottery:pool 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="_1-5-zset-有序集合" tabindex="-1">1.5 ZSet（有序集合） <a class="header-anchor" href="#_1-5-zset-有序集合" aria-label="Permalink to &quot;1.5 ZSet（有序集合）&quot;">​</a></h3><p>⭐ <strong>ZSet 是 Redis 的杀手锏数据结构，排行榜、延迟队列、热搜榜都靠它。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⭐ 底层结构：skiplist（跳表）+ hashtable（字典）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>为什么要同时用两种结构？</span></span>
<span class="line"><span>  - hashtable：按 member 查 score → O(1)</span></span>
<span class="line"><span>  - skiplist：按 score 范围查 member → O(logN)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果只用 skiplist：查 score 需要遍历</span></span>
<span class="line"><span>如果只用 hashtable：范围查询需要全量排序</span></span>
<span class="line"><span>两者组合 → 各取所长</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>跳表结构示意（level = 3）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Level 2:  1 ──────────────────&gt; 9 ──────────────&gt; nil</span></span>
<span class="line"><span>Level 1:  1 ─────&gt; 5 ──────────&gt; 9 ──&gt; 12 ──────&gt; nil</span></span>
<span class="line"><span>Level 0:  1 ─&gt; 3 ─&gt; 5 ─&gt; 7 ─&gt; 9 ─&gt; 10 ─&gt; 12 ─&gt; nil</span></span>
<span class="line"><span></span></span>
<span class="line"><span>查找 score = 10：</span></span>
<span class="line"><span>  L2: 1→9→nil（10在9和nil之间，下降）</span></span>
<span class="line"><span>  L1: 9→12（10在9和12之间，下降）</span></span>
<span class="line"><span>  L0: 9→10 找到！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>时间复杂度：O(logN)</span></span>
<span class="line"><span>空间复杂度：O(N)（每个节点平均 1/(1-p) ≈ 2 个指针，p=0.5）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><table tabindex="0"><thead><tr><th>命令</th><th>说明</th><th>时间复杂度</th></tr></thead><tbody><tr><td><code>ZADD key score member</code></td><td>添加</td><td>O(logN)</td></tr><tr><td><code>ZRANGE key s e [WITHSCORES]</code></td><td>按排名范围查</td><td>O(logN+M)</td></tr><tr><td><code>ZRANGEBYSCORE key min max</code></td><td>按分数范围查</td><td>O(logN+M)</td></tr><tr><td><code>ZRANK key member</code></td><td>查排名</td><td>O(logN)</td></tr><tr><td><code>ZSCORE key member</code></td><td>查分数</td><td>O(1)</td></tr><tr><td><code>ZINCRBY key N member</code></td><td>增减分数</td><td>O(logN)</td></tr><tr><td><code>ZREMRANGEBYRANK key s e</code></td><td>按排名删除</td><td>O(logN+M)</td></tr></tbody></table><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- ⭐ 排行榜（文章热度榜）</span></span>
<span class="line"><span>ZADD hot:articles 1000 article:998 800 article:997 1200 article:996</span></span>
<span class="line"><span>-- 热度 Top 10（倒序取）</span></span>
<span class="line"><span>ZREVRANGE hot:articles 0 9 WITHSCORES</span></span>
<span class="line"><span>-- 给文章加热度</span></span>
<span class="line"><span>ZINCRBY hot:articles 1 article:998</span></span>
<span class="line"><span>-- 查某篇文章的排名</span></span>
<span class="line"><span>ZREVRANK hot:articles article:998</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 延迟队列（score = 执行时间戳）</span></span>
<span class="line"><span>ZADD delay:queue 1718000000 &quot;send_sms:1001&quot;</span></span>
<span class="line"><span>ZADD delay:queue 1718003600 &quot;send_sms:1002&quot;</span></span>
<span class="line"><span>-- 拿到期任务（score &lt;= 当前时间戳）</span></span>
<span class="line"><span>ZRANGEBYSCORE delay:queue 0 1718001800 LIMIT 0 10</span></span>
<span class="line"><span>-- 消费后删除</span></span>
<span class="line"><span>ZREM delay:queue &quot;send_sms:1001&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 为什么 ZSet 用跳表而不是红黑树？</strong></p><p>A: 跳表实现简单（无需复杂的旋转/染色），支持范围查询（<code>ZRANGEBYSCORE</code>），且查找/插入/删除都是 O(logN)。红黑树范围查询需要中序遍历，不如跳表高效。此外跳表天然支持并发（插入只影响相邻节点），Redis 虽单线程，但社区实现（如 Redis 集群）更友好。</p></div><hr><h2 id="二、3-种高级数据类型" tabindex="-1">二、3 种高级数据类型 <a class="header-anchor" href="#二、3-种高级数据类型" aria-label="Permalink to &quot;二、3 种高级数据类型&quot;">​</a></h2><p>⭐ <strong>高级数据类型数量不多，但每个都很精妙。</strong></p><h3 id="_2-1-bitmap-位图" tabindex="-1">2.1 Bitmap（位图） <a class="header-anchor" href="#_2-1-bitmap-位图" aria-label="Permalink to &quot;2.1 Bitmap（位图）&quot;">​</a></h3><p>⭐ <strong>极致节省空间，1 亿用户签到只需 12MB。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原理：</span></span>
<span class="line"><span>  底层就是一个 String，每个 bit 代表一个布尔值</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  用户 ID = 1001，第 1001 位 = 1（已签到）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  offset:   0  1  2  ... 1001 1002 1003 ...</span></span>
<span class="line"><span>  bit:     0  0  0  ...   1    0    1  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>空间计算：1 亿 bit / 8 / 1024 / 1024 ≈ 12 MB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- ⭐ 签到系统</span></span>
<span class="line"><span>-- 用户 1001 在 2024-06-06 签到（第 157 天）</span></span>
<span class="line"><span>SETBIT checkin:20240606 1001 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 查询用户 1001 是否签到</span></span>
<span class="line"><span>GETBIT checkin:20240606 1001   -- 返回 1（已签）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 统计当天签到人数</span></span>
<span class="line"><span>BITCOUNT checkin:20240606</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 连续签到天数（两个 Bitmap 做与运算）</span></span>
<span class="line"><span>BITOP AND result checkin:20240605 checkin:20240606</span></span>
<span class="line"><span>BITCOUNT result   -- 连续两天都签到的用户数</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="_2-2-hyperloglog-基数统计" tabindex="-1">2.2 HyperLogLog（基数统计） <a class="header-anchor" href="#_2-2-hyperloglog-基数统计" aria-label="Permalink to &quot;2.2 HyperLogLog（基数统计）&quot;">​</a></h3><p>⭐ <strong>统计 UV 的神器，12KB 内存即可统计 2^64 个不同元素。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原理：</span></span>
<span class="line"><span>  基于概率算法，使用调和平均数估计基数</span></span>
<span class="line"><span>  标准误差：0.81%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>空间占用：</span></span>
<span class="line"><span>  无论数据量多大，固定 12KB（2^14 个 6bit 寄存器）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- ⭐ 页面 UV 统计</span></span>
<span class="line"><span>PFADD page:home:uv user:1001 user:1002 user:1003 ...</span></span>
<span class="line"><span>PFCOUNT page:home:uv   -- 返回去重后的 UV 数量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 合并多天 UV</span></span>
<span class="line"><span>PFMERGE page:home:uv:week page:home:uv:mon page:home:uv:tue ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><div class="danger custom-block"><p class="custom-block-title">使用注意事项</p><ul><li><code>PFCOUNT</code> 返回的是<strong>估算值</strong>，有 0.81% 误差，不适用于精确计数（如财务审计）</li><li>不适合获取单元素是否存在的判断（用 Set 或 Bitmap）</li><li>数据量大时 <code>PFMERGE</code> 可能较慢</li></ul></div><h3 id="_2-3-geo-地理位置" tabindex="-1">2.3 GEO（地理位置） <a class="header-anchor" href="#_2-3-geo-地理位置" aria-label="Permalink to &quot;2.3 GEO（地理位置）&quot;">​</a></h3><p>⭐ <strong>基于 ZSet 实现，用 GeoHash 编码经纬度为 score。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GeoHash 编码原理：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  地球经度 [-180, 180]，纬度 [-90, 90]</span></span>
<span class="line"><span>  不断二分区间：</span></span>
<span class="line"><span>    0  → 左区间</span></span>
<span class="line"><span>    1  → 右区间</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>  经度 + 纬度交叉编码 → 一个长整数 → ZSet 的 score</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  空间填充曲线：Z 字形，相邻区域 GeoHash 前缀相同</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- ⭐ 附近的人 / LBS 应用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 添加位置（商户、用户等）</span></span>
<span class="line"><span>GEOADD locations 116.404 39.915 &quot;beijing&quot; 121.473 31.230 &quot;shanghai&quot;</span></span>
<span class="line"><span>GEOADD locations 113.264 23.129 &quot;guangzhou&quot; 114.057 22.543 &quot;shenzhen&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 获取经纬度</span></span>
<span class="line"><span>GEOPOS locations beijing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- 计算两地距离</span></span>
<span class="line"><span>GEODIST locations beijing shanghai km   -- 返回约 1067km</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 查附近（北京方圆 2000km 内的城市）</span></span>
<span class="line"><span>GEORADIUS locations 116.404 39.915 2000 km WITHCOORD WITHDIST</span></span>
<span class="line"><span>GEORADIUS locations 116.404 39.915 2000 km ASC COUNT 5  -- 最近 5 个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ⭐ 以&quot;上海&quot;为中心，查附近 300km 内的城市</span></span>
<span class="line"><span>GEORADIUSBYMEMBER locations shanghai 300 km</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><hr><h2 id="三、单线程模型" tabindex="-1">三、单线程模型 <a class="header-anchor" href="#三、单线程模型" aria-label="Permalink to &quot;三、单线程模型&quot;">​</a></h2><p>⭐ <strong>Redis 为什么用单线程还这么快？几乎是必问面试题。</strong></p>`,47)),(a(),l(r,null,{default:n(()=>[i(p,{id:"mermaid-566",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%22Redis%20%E5%8D%95%E7%BA%BF%E7%A8%8B%E4%BA%8B%E4%BB%B6%E5%BE%AA%E7%8E%AF%22%0A%20%20%20%20%20%20%20%20A%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%201%3Cbr%2F%3ESocket%22%5D%20--%3E%20B%5B%22IO%20%E5%A4%9A%E8%B7%AF%E5%A4%8D%E7%94%A8%3Cbr%2F%3E%EF%BC%88epoll%2Fkqueue%2Fselect%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20C%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%202%3Cbr%2F%3ESocket%22%5D%20--%3E%20B%0A%20%20%20%20%20%20%20%20D%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%203%3Cbr%2F%3ESocket%22%5D%20--%3E%20B%0A%20%20%20%20%20%20%20%20B%20--%3E%20E%5B%22%E4%BA%8B%E4%BB%B6%E5%88%86%E5%8F%91%E5%99%A8%3Cbr%2F%3EFileEventHandler%22%5D%0A%20%20%20%20%20%20%20%20E%20--%3E%20F%5B%22%E5%91%BD%E4%BB%A4%E8%A7%A3%E6%9E%90%E5%99%A8%22%5D%0A%20%20%20%20%20%20%20%20F%20--%3E%20G%5B%22%E5%91%BD%E4%BB%A4%E6%89%A7%E8%A1%8C%3Cbr%2F%3E%EF%BC%88%E5%8D%95%E7%BA%BF%E7%A8%8B%EF%BC%89%E2%AD%90%22%5D%0A%20%20%20%20%20%20%20%20G%20--%3E%20H%5B%22%E5%93%8D%E5%BA%94%E8%BF%94%E5%9B%9E%22%5D%0A%20%20%20%20%20%20%20%20H%20--%3E%7C%22%E5%86%99%E5%9B%9E%20Socket%22%7C%20A%0A%20%20%20%20%20%20%20%20H%20--%3E%7C%22%E5%86%99%E5%9B%9E%20Socket%22%7C%20C%0A%20%20%20%20%20%20%20%20H%20--%3E%7C%22%E5%86%99%E5%9B%9E%20Socket%22%7C%20D%0A%20%20%20%20end%0A"})]),fallback:n(()=>[...s[1]||(s[1]=[t(" Loading... ",-1)])]),_:1})),s[4]||(s[4]=e(`<h3 id="_3-1-为什么快" tabindex="-1">3.1 为什么快？ <a class="header-anchor" href="#_3-1-为什么快" aria-label="Permalink to &quot;3.1 为什么快？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原因</th><th>说明</th><th>深度理解</th></tr></thead><tbody><tr><td>⭐ 纯内存操作</td><td>大部分请求在内存中完成</td><td>时间复杂度是关键，O(N) 命令要谨慎</td></tr><tr><td>⭐ 单线程无锁</td><td>无上下文切换、无竞争开销</td><td>实际上 4.0+ 有后台线程（异步删除、AOF 刷盘）</td></tr><tr><td>⭐ IO 多路复用</td><td>epoll 管理海量连接</td><td>一个线程监听多个 Socket，事件驱动</td></tr><tr><td>高效数据结构</td><td>SDS、quicklist、skiplist</td><td>针对 Redis 场景高度优化</td></tr></tbody></table><h3 id="_3-2-单线程的瓶颈" tabindex="-1">3.2 单线程的瓶颈 <a class="header-anchor" href="#_3-2-单线程的瓶颈" aria-label="Permalink to &quot;3.2 单线程的瓶颈&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU 瓶颈：</span></span>
<span class="line"><span>  - 单个 Redis 实例只能利用单核 CPU</span></span>
<span class="line"><span>  - 解决方案：多实例部署（不同端口）+ 集群方案</span></span>
<span class="line"><span></span></span>
<span class="line"><span>慢命令阻塞：</span></span>
<span class="line"><span>  - KEYS *（O(N)全量扫描）</span></span>
<span class="line"><span>  - HGETALL 大 Hash（O(N)返回所有字段）</span></span>
<span class="line"><span>  - DEL 大 Key（4.0 前同步删除会阻塞，4.0+ 用 UNLINK 异步删除）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="danger custom-block"><p class="custom-block-title">生产事故：KEYS *</p><div class="language-redis vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">redis</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- ❌ 绝对禁止在生产环境执行</span></span>
<span class="line"><span>KEYS *</span></span>
<span class="line"><span></span></span>
<span class="line"><span>-- ✅ 使用 SCAN 游标迭代</span></span>
<span class="line"><span>SCAN 0 MATCH user:* COUNT 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一次 <code>KEYS *</code> 可能阻塞数秒，期间所有请求排队等待，极端情况下触发故障转移。</p></div><hr><h2 id="四、使用场景速查表" tabindex="-1">四、使用场景速查表 <a class="header-anchor" href="#四、使用场景速查表" aria-label="Permalink to &quot;四、使用场景速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>数据类型</th><th>Key 设计</th><th>核心命令</th></tr></thead><tbody><tr><td>⭐ 缓存对象</td><td>String</td><td><code>user:info:{uid}</code></td><td>SETEX / GET</td></tr><tr><td>⭐ 分布式锁</td><td>String</td><td><code>lock:order:{oid}</code></td><td>SET NX EX</td></tr><tr><td>⭐ 计数器/限流</td><td>String</td><td><code>counter:pv:{article_id}</code></td><td>INCR / EXPIRE</td></tr><tr><td>⭐ 用户信息</td><td>Hash</td><td><code>user:{uid}</code></td><td>HMSET / HMGET</td></tr><tr><td>⭐ 购物车</td><td>Hash</td><td><code>cart:{uid}</code></td><td>HSET / HINCRBY</td></tr><tr><td>⭐ 消息队列</td><td>List</td><td><code>queue:task</code></td><td>LPUSH / BLPOP</td></tr><tr><td>⭐ 最新列表</td><td>List</td><td><code>timeline:{uid}</code></td><td>LPUSH / LTRIM</td></tr><tr><td>⭐ 用户标签</td><td>Set</td><td><code>tags:{uid}</code></td><td>SADD / SMEMBERS</td></tr><tr><td>⭐ 共同好友</td><td>Set</td><td><code>friend:{uid}</code></td><td>SINTER</td></tr><tr><td>⭐ 抽奖</td><td>Set</td><td><code>lottery:pool</code></td><td>SRANDMEMBER / SPOP</td></tr><tr><td>⭐ 排行榜</td><td>ZSet</td><td><code>rank:score</code></td><td>ZADD / ZREVRANGE</td></tr><tr><td>⭐ 延迟队列</td><td>ZSet</td><td><code>delay:queue</code></td><td>ZADD / ZRANGEBYSCORE</td></tr><tr><td>⭐ 签到</td><td>Bitmap</td><td><code>checkin:{date}</code></td><td>SETBIT / BITCOUNT</td></tr><tr><td>⭐ UV 统计</td><td>HyperLogLog</td><td><code>uv:{page}:{date}</code></td><td>PFADD / PFCOUNT</td></tr><tr><td>⭐ 附近的人</td><td>GEO</td><td><code>geo:shops</code></td><td>GEOADD / GEORADIUS</td></tr><tr><td>Session 共享</td><td>String</td><td><code>session:{token}</code></td><td>SETEX / GET</td></tr></tbody></table><hr><h2 id="五、面试追问合集" tabindex="-1">五、面试追问合集 <a class="header-anchor" href="#五、面试追问合集" aria-label="Permalink to &quot;五、面试追问合集&quot;">​</a></h2><h3 id="q1-redis-的数据-过期策略-是怎样的" tabindex="-1">Q1: Redis 的数据&quot;过期策略&quot;是怎样的？ <a class="header-anchor" href="#q1-redis-的数据-过期策略-是怎样的" aria-label="Permalink to &quot;Q1: Redis 的数据&quot;过期策略&quot;是怎样的？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p><strong>惰性删除 + 定期删除</strong>，两者结合。</p><p><strong>惰性删除</strong>：访问 Key 时检查是否过期，过期则删除。优点：CPU 友好；缺点：内存可能泄露（垃圾 Key 一直不访问）。</p><p><strong>定期删除</strong>：每秒 10 次（<code>hz 10</code>），随机取一批 Key 检查并删除过期的。限制执行时长不超过 25ms。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>定期删除流程：</span></span>
<span class="line"><span>1. 随机取 20 个 Key</span></span>
<span class="line"><span>2. 删除其中过期的</span></span>
<span class="line"><span>3. 如果过期比例 &gt; 25%，继续步骤 1</span></span>
<span class="line"><span>4. 但如果执行时间 &gt; 25ms，强制退出</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><h3 id="q2-redis-的内存淘汰策略有哪些" tabindex="-1">Q2: Redis 的内存淘汰策略有哪些？ <a class="header-anchor" href="#q2-redis-的内存淘汰策略有哪些" aria-label="Permalink to &quot;Q2: Redis 的内存淘汰策略有哪些？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><table tabindex="0"><thead><tr><th>策略</th><th>说明</th></tr></thead><tbody><tr><td><code>noeviction</code></td><td>不淘汰，写请求报错（默认）</td></tr><tr><td><code>allkeys-lru</code></td><td>⭐ 所有 Key 中 LRU 淘汰</td></tr><tr><td><code>volatile-lru</code></td><td>过期 Key 中 LRU 淘汰</td></tr><tr><td><code>allkeys-lfu</code></td><td>⭐ 所有 Key 中 LFU 淘汰（4.0+）</td></tr><tr><td><code>volatile-lfu</code></td><td>过期 Key 中 LFU 淘汰（4.0+）</td></tr><tr><td><code>allkeys-random</code></td><td>所有 Key 随机淘汰</td></tr><tr><td><code>volatile-random</code></td><td>过期 Key 随机淘汰</td></tr><tr><td><code>volatile-ttl</code></td><td>过期 Key 中 TTL 最短的淘汰</td></tr></tbody></table><p>LRU vs LFU：</p><ul><li>LRU：最近最少使用（适合时效性强的热点数据）</li><li>LFU：最不常使用（适合高频访问数据，防止偶发性冷数据挤掉热数据）</li></ul></details><h3 id="q3-大-key-有什么危害-如何发现和处理" tabindex="-1">Q3: 大 Key 有什么危害？如何发现和处理？ <a class="header-anchor" href="#q3-大-key-有什么危害-如何发现和处理" aria-label="Permalink to &quot;Q3: 大 Key 有什么危害？如何发现和处理？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p><strong>危害</strong>：</p><ul><li>读取阻塞：单次操作耗时过长（如 <code>HGETALL</code> 返回百万条）</li><li>删除阻塞：<code>DEL</code> 大 Key 时阻塞主线程</li><li>迁移困难：集群迁移 / 主从同步耗时</li><li>内存倾斜：某些分片内存使用率过高</li></ul><p><strong>发现方式</strong>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Redis 自带的 BigKeys 扫描</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">redis-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bigkeys</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 分析 RDB 文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dump.rdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bytes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10240</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory.csv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>处理方案</strong>：</p><ul><li><code>UNLINK</code>（4.0+）替代 <code>DEL</code>（异步删除，非阻塞）</li><li>Hash 大 Key：按 field 拆分（<code>user:{uid}:info</code>）</li><li>List 大 Key：按日期分片（<code>timeline:{uid}:{month}</code>）</li><li>Set/ZSet 大 Key：按 hash tag 路由到不同分片</li></ul></details><hr><h2 id="六、生产实践建议" tabindex="-1">六、生产实践建议 <a class="header-anchor" href="#六、生产实践建议" aria-label="Permalink to &quot;六、生产实践建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">黄金法则</p><ol><li><strong>Key 命名规范</strong>：<code>业务:模块:标识</code>（如 <code>order:detail:1001</code>），禁止无意义 Key</li><li><strong>必须设过期时间</strong>：除少数持久化场景，所有 Key 加 TTL</li><li><strong>禁用危险命令</strong>：<code>RENAME</code> 命令将 <code>KEYS / FLUSHALL / FLUSHDB</code> 改名</li><li><strong>Pipeline 批量操作</strong>：减少网络 RTT（Round-Trip Time），但注意单次 Pipeline 不要过大</li><li><strong>连接池合理配置</strong>：<code>maxTotal</code> = 业务峰值 QPS / 单 Redis 实例 QPS 极限 × 1.5</li><li><strong>慢查询监控</strong>：<code>slowlog get 100</code>，关注超过 1ms 的命令</li><li><strong>内存规划</strong>：预留 30% 内存给 fork 操作（bgsave / rewrite）</li></ol></div><hr><h2 id="相关面试题速记" tabindex="-1">相关面试题速记 <a class="header-anchor" href="#相关面试题速记" aria-label="Permalink to &quot;相关面试题速记&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Redis 为什么快？</span></span>
<span class="line"><span>  → 纯内存 + 单线程无锁 + IO 多路复用 + 高效数据结构</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ZSet 底层是什么？</span></span>
<span class="line"><span>  → skiplist + hashtable（范围查 + 精确查）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Redis 怎么做分布式锁？</span></span>
<span class="line"><span>  → SET NX EX + Lua 解锁 / Redisson（续期 + 可重入）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>缓存穿透/击穿/雪崩怎么解决？</span></span>
<span class="line"><span>  → 穿透：布隆过滤器 / 空值缓存</span></span>
<span class="line"><span>  → 击穿：互斥锁 / 永不过期</span></span>
<span class="line"><span>  → 雪崩：随机 TTL / 多级缓存 / 限流降级</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Redis 持久化方式？</span></span>
<span class="line"><span>  → RDB（快照，bgsave fork 子进程）</span></span>
<span class="line"><span>  → AOF（写日志，everysec 策略）</span></span>
<span class="line"><span>  → 混合持久化（4.0+，RDB + AOF 补增量）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div>`,22))])}const A=d(o,[["render",u]]);export{B as __pageData,A as default};
